mapper.select:
SELECT u.user_id, u.username, u.real_name, u.email, u.phone, u.gender, u.dept_id, d.dept_name, u.position, u.status, u.balance, u.remark, u.create_time, u.update_time FROM sys_user u LEFT JOIN sys_department d ON u.dept_id = d.dept_id WHERE u.deleted = 0
AND u.username LIKE CONCAT('%', #{query.username}, '%')
AND u.real_name LIKE CONCAT('%', #{query.realName}, '%')
AND u.email LIKE CONCAT('%', #{query.email}, '%')
AND u.phone LIKE CONCAT('%', #{query.phone}, '%')
AND u.gender = #{query.gender}
AND u.dept_id = #{query.deptId}
AND u.status = #{query.status}
ORDER BY u.create_time DESC
